// Parse Remotive API response
const jobs = $input.first().json.jobs || [];

return jobs
  .filter(job => {
    const text = `${job.title} ${job.description || ''} ${job.category || ''}`.toLowerCase();
    const hasDevKeyword = ['developer', 'engineer', 'backend', 'php', 'laravel', 'symfony', 'software'].some(kw => text.includes(kw));
    const isExcluded = ['wordpress only', 'ios developer', 'android developer', 'mobile developer'].some(kw => text.includes(kw));
    return hasDevKeyword && !isExcluded;
  })
  .slice(0, 50)
  .map(job => ({
    json: {
      title: job.title,
      company: job.company_name,
      url: job.url,
      description: job.description,
      source: 'remotive',
      location: job.candidate_required_location || 'Remote',
      salary: job.salary || null,
      category: job.category
    }
  }));

// Parse WWR RSS (XML text)
const text = $input.first().json.data || $input.first().json.body || '';

const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;

while ((match = itemRegex.exec(text)) !== null) {
  const item = match[1];
  const title = (item.match(/<title><!\[CDATA\[(.+?)\]\]><\/title>/) || item.match(/<title>(.+?)<\/title>/) || [])[1] || '';
  const link = (item.match(/<link>(.+?)<\/link>/) || [])[1] || '';
  const description = (item.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/) || item.match(/<description>([\s\S]*?)<\/description>/) || [])[1] || '';

  if (title && link) {
    const text = `${title} ${description}`.toLowerCase();
    const hasDevKeyword = ['developer', 'engineer', 'backend', 'php', 'laravel', 'symfony', 'software'].some(kw => text.includes(kw));
    const isExcluded = ['wordpress only', 'ios developer', 'android developer'].some(kw => text.includes(kw));

    if (hasDevKeyword && !isExcluded) {
      // Extract company from title (format: "Title: Company")
      const parts = title.split(':');
      const jobTitle = parts[0]?.trim() || title;
      const company = parts[1]?.trim() || 'Unknown';

      items.push({
        json: {
          title: jobTitle,
          company: company,
          url: link,
          description: description.replace(/<[^>]*>/g, ' ').trim(),
          source: 'weworkremotely',
          location: 'Remote',
          salary: null,
          category: 'programming'
        }
      });
    }
  }
}

return items.slice(0, 30);

// Parse Arbeitnow API response
const jobs = $input.first().json.data || [];

return jobs
  .filter(job => {
    const text = `${job.title} ${job.description || ''} ${job.tags?.join(' ') || ''}`.toLowerCase();
    const hasDevKeyword = ['developer', 'engineer', 'backend', 'php', 'laravel', 'symfony', 'software', 'programming'].some(kw => text.includes(kw));
    const isRemote = job.remote === true || text.includes('remote');
    const isExcluded = ['wordpress only', 'ios developer', 'android developer'].some(kw => text.includes(kw));
    return hasDevKeyword && isRemote && !isExcluded;
  })
  .slice(0, 30)
  .map(job => ({
    json: {
      title: job.title,
      company: job.company_name,
      url: job.url,
      description: job.description,
      source: 'arbeitnow',
      location: job.location || 'Remote',
      salary: job.salary || null,
      category: job.tags?.join(', ') || null
    }
  }));

// Filter out already known URLs
const knownUrlsItem = $('Get Known URLs').first();
const knownUrls = new Set(knownUrlsItem?.json?.urls || []);

const allJobs = $('Merge All Jobs').all();
const newJobs = allJobs.filter(item => !knownUrls.has(item.json.url));

console.log(`Total jobs: ${allJobs.length}, New jobs: ${newJobs.length}`);

return newJobs;

const jobs = $input.all().map(i => i.json);
if (jobs.length === 0) {
  throw new Error('No new jobs to ingest');
}
return [{ json: { jobs } }];

// Requires n8n env var: N8N_WEBHOOK_SECRET
// Set in n8n Settings > Environment Variables
const secret = $env.N8N_WEBHOOK_SECRET;
if (!secret) throw new Error('Set N8N_WEBHOOK_SECRET in n8n environment variables');

const jobs = $input.first().json.jobs;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://job-agent-eosin.vercel.app/api/jobs/ingest',
  headers: {
    Authorization: `Bearer ${secret}`,
    'Content-Type': 'application/json',
  },
  body: jobs,
  json: true,
});

return [{ json: response }];
